#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int num_favorable = (int)ceil((double)N/2) * (int)floor((double)M/2) + (int)floor((double)N/2) * (int)ceil((double)M/2);
        int total_outcomes = N * M;
        int gcd = gcd_of_two_numbers(num_favorable, total_outcomes);
        printf("%d/%d\n", num_favorable/gcd, total_outcomes/gcd);
    }
    return 0;
}

int gcd_of_two_numbers(int a, int b) {
    if (b == 0)
        return a;
    return gcd_of_two_numbers(b, a % b);
}

