import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int num_favorable = (int)Math.ceil((double)N/2) * (int)Math.floor((double)M/2) + (int)Math.floor((double)N/2) * (int)Math.ceil((double)M/2);
            int total_outcomes = N * M;
            int gcd = gcd_of_two_numbers(num_favorable, total_outcomes);
            System.out.println(num_favorable/gcd + "/" + total_outcomes/gcd);
        }
    }
    public static int gcd_of_two_numbers(int a, int b) {
        if (b == 0)
            return a;
        return gcd_of_two_numbers(b, a % b);
    }
}

