const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, M] = readline().split(' ').map(x => parseInt(x));
    const num_favorable = Math.ceil(N/2) * Math.floor(M/2) + Math.floor(N/2) * Math.ceil(M/2);
    const total_outcomes = N * M;
    const gcd = (a, b) => b === 0 ? a : gcd(b, a % b);
    const g = gcd(num_favorable, total_outcomes);
    console.log(`${num_favorable/g}/${total_outcomes/g}`);
}
